#[cfg(test)]
mod filesystem_tests {
    use super::*;
    use tempfile::TempDir;

    fn setup_test_dir() -> TempDir {
        let dir = TempDir::new().unwrap();
        std::fs::write(dir.path().join("readme.md"), "# Test").unwrap();
        std::fs::write(dir.path().join("data.json"), r#"{"key":"value"}"#).unwrap();
        std::fs::create_dir(dir.path().join("subdir")).unwrap();
        std::fs::write(dir.path().join("subdir/nested.txt"), "nested content").unwrap();
        std::fs::write(dir.path().join(".hidden"), "hidden file").unwrap();
        dir
    }

    #[test]
    fn test_list_files_in_root() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path()).build();

        let files = provider.list_resources().unwrap();
        assert!(files.iter().any(|f| f.uri.contains("readme.md")));
        assert!(files.iter().any(|f| f.uri.contains("data.json")));
    }

    #[test]
    fn test_exclude_hidden_files() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path())
            .with_exclude(&[".*"])
            .build();

        let files = provider.list_resources().unwrap();
        assert!(!files.iter().any(|f| f.uri.contains(".hidden")));
    }

    #[test]
    fn test_include_patterns() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path())
            .with_patterns(&["*.md"])
            .build();

        let files = provider.list_resources().unwrap();
        assert!(files.iter().all(|f| f.uri.ends_with(".md")));
    }

    #[test]
    fn test_recursive_listing() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path())
            .with_recursive(true)
            .build();

        let files = provider.list_resources().unwrap();
        assert!(files.iter().any(|f| f.uri.contains("subdir/nested.txt")));
    }

    #[test]
    fn test_non_recursive_excludes_subdirs() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path())
            .with_recursive(false)
            .build();

        let files = provider.list_resources().unwrap();
        assert!(!files.iter().any(|f| f.uri.contains("nested.txt")));
    }

    #[test]
    fn test_read_file_content() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path()).build();

        let content = provider.read_resource("readme.md").unwrap();
        assert_eq!(content.contents[0].as_text(), Some("# Test"));
    }

    #[test]
    fn test_mime_type_detection() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path()).build();

        let md = provider.read_resource("readme.md").unwrap();
        assert!(md.contents[0].mime_type.as_ref().unwrap().contains("markdown"));

        let json = provider.read_resource("data.json").unwrap();
        assert!(json.contents[0].mime_type.as_ref().unwrap().contains("json"));
    }

    #[test]
    fn test_path_traversal_rejected() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path()).build();

        let result = provider.read_resource("../../../etc/passwd");
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), ResourceError::PathTraversal));
    }

    #[test]
    fn test_max_file_size_enforced() {
        let dir = setup_test_dir();
        std::fs::write(dir.path().join("large.bin"), vec![0u8; 1024]).unwrap();

        let provider = FilesystemProvider::new(dir.path())
            .with_max_size(512)
            .build();

        let result = provider.read_resource("large.bin");
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), ResourceError::TooLarge { .. }));
    }

    #[test]
    fn test_prefix_applied_to_uris() {
        let dir = setup_test_dir();
        let provider = FilesystemProvider::new(dir.path())
            .with_prefix("docs")
            .build();

        let files = provider.list_resources().unwrap();
        assert!(files.iter().all(|f| f.uri.starts_with("file://docs/")));
    }

    #[test]
    fn test_symlink_not_followed_by_default() {
        let dir = setup_test_dir();
        // Create symlink pointing outside root
        #[cfg(unix)]
        std::os::unix::fs::symlink("/etc/passwd", dir.path().join("escape")).unwrap();

        let provider = FilesystemProvider::new(dir.path()).build();

        let result = provider.read_resource("escape");
        assert!(result.is_err());
    }
}
