//! Integration tests for FilesystemProvider

use fastmcp_server::{Server, ServerBuilder, FilesystemProvider};
use tempfile::TempDir;

fn create_test_filesystem() -> TempDir {
    let dir = TempDir::new().unwrap();
    std::fs::write(dir.path().join("config.json"), r#"{"port": 8080}"#).unwrap();
    std::fs::write(dir.path().join("readme.md"), "# Documentation").unwrap();
    std::fs::create_dir_all(dir.path().join("templates")).unwrap();
    std::fs::write(dir.path().join("templates/email.html"), "<html>...</html>").unwrap();
    dir
}

#[tokio::test]
async fn test_filesystem_provider_in_server() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_prefix("data")
        .with_recursive(true)
        .build();

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .build();

    let resources = server.list_resources().await.unwrap();
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/config.json"));
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/readme.md"));
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/templates/email.html"));
}

#[tokio::test]
async fn test_read_filesystem_resource() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_prefix("files")
        .build();

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .build();

    let result = server.read_resource("file://files/config.json").await.unwrap();
    let text = result.contents[0].as_text().unwrap();
    assert!(text.contains("8080"));
}

#[tokio::test]
async fn test_tool_uses_filesystem_resource() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_prefix("config")
        .build();

    #[tool]
    async fn load_config(ctx: &McpContext) -> Result<String, ToolError> {
        let config = ctx.read_resource_text("file://config/config.json").await?;
        Ok(format!("Loaded: {}", config))
    }

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .tool(load_config)
        .build();

    let result = server.call_tool("load_config", json!({})).await.unwrap();
    assert!(result.content[0].as_text().unwrap().contains("8080"));
}

#[tokio::test]
async fn test_filesystem_with_watch() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_watch(true)
        .build();

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .build();

    // Subscribe to changes
    let mut changes = server.subscribe_resource_changes().await;

    // Modify a file
    std::fs::write(dir.path().join("config.json"), r#"{"port": 9090}"#).unwrap();

    // Should receive notification
    let notification = tokio::time::timeout(
        Duration::from_secs(1),
        changes.recv()
    ).await.unwrap().unwrap();

    assert!(notification.uri.contains("config.json"));
}
