LOG_FILE="/tmp/fastmcp_error_masking_e2e_$(date +%Y%m%d_%H%M%S).log"

log() {
    local level="$1"
    shift
    echo "[$(date +%H:%M:%S)] [$level] $*" | tee -a "$LOG_FILE"
}

log "INFO" "=== FastMCP Error Masking E2E Test ==="
log "INFO" "Log file: $LOG_FILE"

# Build test servers
log "INFO" "Building test servers..."
cargo build --example error_masking_server 2>&1 | tee -a "$LOG_FILE"

SERVER="./target/debug/examples/error_masking_server"

# Standard init
INIT='{"jsonrpc":"2.0","id":1,"method":"initialize","params":{"protocolVersion":"2024-11-05","clientInfo":{"name":"test","version":"1.0"}}}'
INITIALIZED='{"jsonrpc":"2.0","method":"initialized"}'

# Test 1: Masked mode hides details
log "INFO" "Test 1: Masked mode hides internal error details"
CALL='{"jsonrpc":"2.0","id":2,"method":"tools/call","params":{"name":"leaky_tool","arguments":{}}}'

RESPONSE=$(FASTMCP_MASK_ERRORS=true echo -e "$INIT\n$INITIALIZED\n$CALL" | $SERVER 2>>"$LOG_FILE" | grep '"id":2')
log "DEBUG" "Masked response: $RESPONSE"

# Should NOT contain sensitive info
if echo "$RESPONSE" | grep -q "password\|/etc/\|postgres://"; then
    log "ERROR" "FAIL: Sensitive info leaked in masked mode"
    exit 1
else
    log "INFO" "PASS: Sensitive info hidden in masked mode"
fi

# Test 2: Unmasked mode shows details
log "INFO" "Test 2: Unmasked mode shows error details"

RESPONSE=$(FASTMCP_MASK_ERRORS=false echo -e "$INIT\n$INITIALIZED\n$CALL" | $SERVER 2>>"$LOG_FILE" | grep '"id":2')
log "DEBUG" "Unmasked response: $RESPONSE"

# Should contain detailed info
if echo "$RESPONSE" | grep -q "database\|config"; then
    log "INFO" "PASS: Details visible in unmasked mode"
else
    log "WARN" "SKIP: Details check inconclusive"
fi

# Test 3: Client errors not masked
log "INFO" "Test 3: Client errors preserved in masked mode"
